  1→import fs from "node:fs";
  2→import path from "node:path";
  3→import type { V3Options } from "../types/public/index.js";
  4→import {
  5→  EventSink,
  6→  JsonlFileEventSink,
  7→  PrettyLogFileEventSink,
  8→  PrettyStderrEventSink,
  9→  ShallowInMemoryEventSink,
 10→} from "./EventSink.js";
 11→import { FlowEvent } from "./FlowLogger.js";
 12→
 13→const DEFAULT_IN_MEMORY_EVENT_LIMIT = 500; // Per-session ancestry window retained by the default shallow query sink.
 14→const CONFIG_DIR = process.env.BROWSERBASE_CONFIG_DIR || ""; // Base directory for session metadata + file-backed flow logs.
 15→const FLOW_LOGS_ENABLED = process.env.BROWSERBASE_FLOW_LOGS === "1"; // Force-enables the pretty stderr flow sink even when `verbose !== 2`.
 16→const SENSITIVE_KEYS =
 17→  /key|secret|token|api-key|apikey|api_key|password|passwd|pwd|credential|auth/i; // Redacts obvious secrets before session options are written to disk.
 18→
 19→// =============================================================================
 20→// Public Contracts
 21→// =============================================================================
 22→
 23→export interface EventStoreQuery {
 24→  sessionId?: string;
 25→  eventId?: string;
 26→  eventType?: string;
 27→  limit?: number;
 28→}
 29→
 30→export interface EventStoreApi {
 31→  readonly sessionId: string;
 32→  emit(event: FlowEvent): Promise<void>;
 33→  query(query: EventStoreQuery): Promise<FlowEvent[]>;
 34→  destroy(): Promise<void>;
 35→}
 36→
 37→// =============================================================================
 38→// Filesystem Helpers
 39→// =============================================================================
 40→
 41→// Redacts secrets before session options are written to `session.json` inside a config-dir-backed session directory.
 42→function sanitizeOptions(options: V3Options): Record<string, unknown> {
 43→  const sanitize = (value: unknown): unknown => {
 44→    if (typeof value !== "object" || value === null) return value;
 45→    if (Array.isArray(value)) return value.map(sanitize);
 46→
 47→    const result: Record<string, unknown> = {};
 48→    for (const [key, entry] of Object.entries(value)) {
 49→      result[key] = SENSITIVE_KEYS.test(key) ? "******" : sanitize(entry);
 50→    }
 51→    return result;
 52→  };
 53→
 54→  return sanitize({ ...options }) as Record<string, unknown>;
 55→}
 56→
 57→// Resolves the configured Browserbase config directory used by file sinks.
 58→export function getConfigDir(): string {
 59→  return CONFIG_DIR ? path.resolve(CONFIG_DIR) : "";
 60→}
 61→
 62→// Creates the per-session directory used by file sinks and writes best-effort metadata such as the sanitized `session.json` file and `latest` symlink.
 63→async function createSessionDir(
 64→  sessionId: string,
 65→  options?: V3Options,
 66→): Promise<string | null> {
 67→  const configDir = getConfigDir();
 68→  if (!configDir) {
 69→    return null;
 70→  }
 71→
 72→  const sessionDir = path.join(configDir, "sessions", sessionId);
 73→  await fs.promises.mkdir(sessionDir, { recursive: true });
 74→
 75→  if (options) {
 76→    await fs.promises.writeFile(
 77→      path.join(sessionDir, "session.json"),
 78→      JSON.stringify(sanitizeOptions(options), null, 2),
 79→      "utf-8",
 80→    );
 81→  }
 82→
 83→  const latestLink = path.join(configDir, "sessions", "latest");
 84→  try {
 85→    try {
 86→      await fs.promises.unlink(latestLink);
 87→    } catch {
 88→      // ignore missing link
 89→    }
 90→    await fs.promises.symlink(sessionId, latestLink, "dir");
 91→  } catch {
 92→    // symlink best effort only
 93→  }
 94→
 95→  return sessionDir;
 96→}
 97→
 98→// =============================================================================
 99→// Event Store
100→// =============================================================================
101→
102→// Per-session flow event sink manager.
103→// This is not an event bus. V3 forwards already-emitted FlowEvents into it so
104→// the store can fan them out to configured sinks, answer `query()` calls from
105→// its one query sink, and tear down its sinks when the session closes.
106→// We keep this as a separate object instead of wiring sinks directly with
107→// `v3.bus.on("*", sink.emit)` because pretty sinks need access to a shared
108→// query interface while rendering. Prettified lines often need to look up
109→// related parent/child events to recover the readable ancestry tags and labels.
110→// Passing sinks into each other to share that state gets messy quickly, so the
111→// EventStore contains the circular dependency: all sinks live here, and any
112→// sink that needs historical context can call the one `EventStore.query()`
113→// entrypoint backed by the main query sink for this session.
114→export class EventStore implements EventStoreApi {
115→  private readonly sinks = new Set<EventSink>(); // All sinks attached for this session; constructor registers them here and `destroy()` tears them down.
116→  private destroyed = false; // Flipped by `destroy()` so later emits and teardown calls become no-ops.
117→  public query: (query: EventStoreQuery) => Promise<FlowEvent[]>; // Always reads from the one query sink chosen at construction time.
118→
119→  // Creates the per-instance store owned by a single V3 session. This store is intentionally single-session; it ignores events for other session ids.
120→  constructor(
121→    // Usually matches `browserbaseSessionId` today, but it is the store's own Stagehand session identifier and may diverge in the future.
122→    public readonly sessionId: string,
123→    options?: V3Options,
124→    querySink: EventSink = new ShallowInMemoryEventSink(
125→      DEFAULT_IN_MEMORY_EVENT_LIMIT,
126→    ),
127→  ) {
128→    const sessionDirPromise = createSessionDir(sessionId, options);
129→
130→    this.registerSink(querySink);
131→    this.query = async (query) => {
132→      if (query.sessionId && query.sessionId !== this.sessionId) {
133→        return [];
134→      }
135→
136→      return querySink.query({
137→        ...query,
138→        sessionId: this.sessionId,
139→      });
140→    };
141→
142→    if (getConfigDir()) {
143→      this.registerSink(new JsonlFileEventSink(sessionDirPromise));
144→      this.registerSink(new PrettyLogFileEventSink(sessionDirPromise, this));
145→    }
146→
147→    if (options?.verbose === 2 || FLOW_LOGS_ENABLED) {
148→      this.registerSink(new PrettyStderrEventSink(this));
149→    }
150→  }
151→
152→  // Adds a sink to the direct fanout list used by `emit()`.
153→  private registerSink(sink: EventSink): void {
154→    this.sinks.add(sink);
155→  }
156→
157→  // Emits an event to all attached sinks when it belongs to this store's single session.
158→  emit = async (event: FlowEvent): Promise<void> => {
159→    if (!(event instanceof FlowEvent)) {
160→      return;
161→    }
162→
163→    if (this.destroyed || event.sessionId !== this.sessionId) {
164→      return;
165→    }
166→
167→    await Promise.allSettled([...this.sinks].map((sink) => sink.emit(event)));
168→  };
169→
170→  // Tears down all sinks when the V3 instance is closed.
171→  async destroy(): Promise<void> {
172→    if (this.destroyed) {
173→      return;
174→    }
175→
176→    this.destroyed = true;
177→    await Promise.all(
178→      [...this.sinks].map((sink) =>
179→        sink.destroy().catch(() => {
180→          // best effort cleanup
181→        }),
182→      ),
183→    );
184→    this.sinks.clear();
185→  }
186→}
