  1→import { AsyncLocalStorage } from "node:async_hooks";
  2→import { v7 as uuidv7 } from "uuid";
  3→import type { LanguageModelMiddleware } from "ai";
  4→import { z } from "zod";
  5→import { EventEmitterWithWildcardSupport } from "./EventEmitter.js";
  6→
  7→// =============================================================================
  8→// Flow Event Model
  9→// =============================================================================
 10→
 11→export const FlowEventDataSchema = z.record(z.string(), z.unknown());
 12→export const FlowEventInputSchema = z.object({
 13→  eventType: z.string(),
 14→  eventId: z.string().optional(),
 15→  eventParentIds: z.array(z.string()).optional(),
 16→  eventCreatedAt: z.string().optional(),
 17→  sessionId: z.string().optional(),
 18→  data: FlowEventDataSchema.optional(),
 19→});
 20→
 21→export type FlowEventData = z.infer<typeof FlowEventDataSchema>;
 22→export type FlowEventInput = z.input<typeof FlowEventInputSchema>;
 23→
 24→// the same as FlowEventInput, but with all fields required (non-optional)
 25→type FlowEventFields = Omit<
 26→  FlowEventInput,
 27→  "eventId" | "eventParentIds" | "eventCreatedAt" | "sessionId" | "data"
 28→> & {
 29→  eventId: string;
 30→  eventParentIds: string[];
 31→  eventCreatedAt: string;
 32→  sessionId: string;
 33→  data: FlowEventData;
 34→};
 35→
 36→export class FlowEvent implements FlowEventFields {
 37→  // "ModuleMethodSomethingEvent" -> hashToSmallInt("Modu) -> 5. eventId = "...5"
 38→  private static deriveEventIdSuffix(eventType: string): string {
 39→    const prefixMatch = eventType.match(/^[A-Z][a-z0-9]*/);
 40→    const prefix = prefixMatch?.[0] ?? eventType.slice(0, 4);
 41→
 42→    let hash = 0;
 43→    for (const ch of prefix.slice(0, 4)) {
 44→      hash = (hash * 31 + ch.charCodeAt(0)) % 10;
 45→    }
 46→    return String(hash); // e.g. "0" or "9"
 47→  }
 48→
 49→  // Builds a sortable UUID-like event id while preserving a stable, human-friendly suffix derived from the event family.
 50→  static createEventId(eventType: string): string {
 51→    const rawEventId = uuidv7();
 52→    return `${rawEventId.slice(0, -1)}${FlowEvent.deriveEventIdSuffix(eventType)}`;
 53→  }
 54→
 55→  // Base required fields for all events:
 56→  eventType: string;
 57→  eventId: string;
 58→  eventParentIds: string[];
 59→  eventCreatedAt: string;
 60→  // `sessionId` usually matches `browserbaseSessionId` today, but FlowLogger treats it as a generic Stagehand session identifier because those may diverge in the future.
 61→  sessionId: string;
 62→  data: FlowEventData; // event payload (e.g. params, action, result, error, etc.)
 63→
 64→  // Normalizes the event shape used everywhere in the flow logger pipeline. This is called at emission time right before an event is attached to the event bus and any sinks.
 65→  constructor(input: FlowEventInput) {
 66→    if (!input.sessionId) {
 67→      throw new Error("FlowEvent.sessionId is required.");
 68→    }
 69→    if (input.eventType.endsWith("Event")) {
 70→      this.eventType = input.eventType;
 71→    } else {
 72→      this.eventType = `${input.eventType}Event`;
 73→    }
 74→    this.eventId = input.eventId ?? FlowEvent.createEventId(this.eventType);
 75→    this.eventParentIds = input.eventParentIds ?? [];
 76→    this.eventCreatedAt = input.eventCreatedAt ?? new Date().toISOString();
 77→    this.sessionId = input.sessionId;
 78→    this.data = input.data ?? {};
 79→  }
 80→}
 81→
 82→export interface FlowLoggerContext {
 83→  // Mirrors `FlowEvent.sessionId`; it is currently the Stagehand session id and often matches `browserbaseSessionId`, but callers should not rely on that.
 84→  sessionId: string;
 85→  eventBus: EventEmitterWithWildcardSupport; // Shared per-session bus; `emit()` writes to it and V3 forwards wildcard events into the instance-owned EventStore.
 86→  parentEvents: FlowEvent[]; // Active parent stack for the current async chain; wrappers push/pop this as logged work starts and ends.
 87→}
 88→
 89→type AsyncOriginalMethod<
 90→  TArgs extends unknown[] = unknown[],
 91→  TResult = unknown,
 92→  TThis = unknown,
 93→> = (this: TThis, ...args: TArgs) => Promise<TResult>;
 94→
 95→type FlowLoggerLogOptions = FlowEventInput & {
 96→  context?: FlowLoggerContext;
 97→};
 98→
 99→// AsyncLocalStorage is the authoritative source for the active flow parent stack inside a single async call-chain.
100→const loggerContext = new AsyncLocalStorage<FlowLoggerContext>();
101→
102→// Converts raw inline image/base64 payload lengths into a compact kb string for LLM prompt summaries.
103→function dataToKb(data: string): string {
104→  return ((data.length * 0.75) / 1024).toFixed(1);
105→}
106→
107→// =============================================================================
108→// Flow Logger Internals
109→// =============================================================================
110→
111→type CdpLogEventType = "call" | "response" | "responseError" | "message";
112→
113→type CdpLogPayload = {
114→  method: string;
115→  params?: unknown;
116→  result?: unknown;
117→  error?: string;
118→  targetId?: string | null;
119→};
120→
121→const CDP_EVENT_NAMES: Record<CdpLogEventType, string> = {
122→  call: "CdpCallEvent",
123→  response: "CdpResponseEvent",
124→  responseError: "CdpResponseErrorEvent",
125→  message: "CdpMessageEvent",
126→};
127→
128→export class FlowLogger {
129→  // Copies the mutable parts of a context before it is re-entered in a later async callback. This prevents later parent-stack mutations from leaking backward into stored snapshots.
130→  private static cloneContext(ctx: FlowLoggerContext): FlowLoggerContext {
131→    return {
132→      ...ctx,
133→      parentEvents: ctx.parentEvents.map((event) => ({
134→        ...event,
135→        eventParentIds: [...event.eventParentIds],
136→      })),
137→    };
138→  }
139→
140→  // Chooses the safest context to re-enter when callers already have a stored context
141→  // and ALS may or may not already contain one for the same session.
142→  // If the current ALS stack extends the stored stack, we keep the richer ALS view.
143→  // If the stored stack is deeper, we preserve that instead.
144→  // If they diverge, we prefer the current ALS view because it reflects the currently executing call-chain.
145→  private static resolveReentryContext(
146→    context: FlowLoggerContext,
147→  ): FlowLoggerContext {
148→    const currentContext = loggerContext.getStore() ?? null;
149→    // If ALS is empty or belongs to another session, the caller's stored
150→    // snapshot is the only safe context we can re-enter.
151→    if (!currentContext || currentContext.sessionId !== context.sessionId) {
152→      return FlowLogger.cloneContext(context);
153→    }
154→
155→    const providedParentIds = context.parentEvents.map(
156→      (event) => event.eventId,
157→    );
158→    const currentParentIds = currentContext.parentEvents.map(
159→      (event) => event.eventId,
160→    );
161→    const currentExtendsProvided = providedParentIds.every(
162→      (eventId, index) => currentParentIds[index] === eventId,
163→    );
164→    // ALS already has the provided chain as a prefix, so we keep the richer
165→    // currently-executing stack instead of truncating it.
166→    if (currentExtendsProvided) {
167→      return FlowLogger.cloneContext(currentContext);
168→    }
169→
170→    const providedExtendsCurrent = currentParentIds.every(
171→      (eventId, index) => providedParentIds[index] === eventId,
172→    );
173→    // The stored snapshot is deeper than the current ALS stack, which usually
174→    // means we are re-entering from a later async callback and need to restore
175→    // the missing parent chain.
176→    if (providedExtendsCurrent) {
177→      return FlowLogger.cloneContext(context);
178→    }
179→
180→    // If the two chains diverged, prefer the live ALS chain because it reflects
181→    // the work currently executing on this async path.
182→    return FlowLogger.cloneContext(currentContext);
183→  }
184→
185→  // Materializes and emits a single flow event on the active ALS context.
186→  // This is the lowest-level write path used by all higher-level logging helpers
187→  // after they have decided which parent chain and session the event belongs to.
188→  private static emit(event: FlowEventInput): FlowEvent | null {
189→    const ctx = FlowLogger.currentContext;
190→
191→    const emittedEvent = new FlowEvent({
192→      ...event,
193→      eventParentIds:
194→        event.eventParentIds ??
195→        ctx.parentEvents.map((parent) => parent.eventId),
196→      sessionId: ctx.sessionId,
197→    });
198→    ctx.eventBus.emit(emittedEvent.eventType, emittedEvent);
199→    return emittedEvent;
200→  }
201→
202→  // Wraps a unit of async work with started/completed/error events while maintaining
203→  // the parent stack inside the active context.
204→  private static async runWithAutoStatusEventLogging<TResult>(
205→    options: FlowLoggerLogOptions,
206→    originalMethod: AsyncOriginalMethod<[], TResult>,
207→  ): Promise<TResult> {
208→    const ctx = FlowLogger.currentContext;
209→    const { data, eventParentIds, eventType } = options;
210→    let caughtError: unknown = null;
211→
212→    // if eventParentIds is explicitly [], this is a root event, clear the parent events in context
213→    if (eventParentIds && eventParentIds.length === 0) {
214→      ctx.parentEvents = [];
215→    }
216→
217→    const startedEvent = FlowLogger.emit({
218→      eventType,
219→      data,
220→      eventParentIds,
221→    });
222→
223→    // Push after emitting so nested work sees this event as its direct parent
224→    // for the rest of the wrapped method's lifetime.
225→    ctx.parentEvents.push(startedEvent);
226→
227→    try {
228→      return await originalMethod();
229→    } catch (error) {
230→      caughtError = error;
231→      // Error events attach directly under the started event even though the
232→      // stack is still live, so the failure edge is explicit in the tree.
233→      FlowLogger.emit({
234→        eventType: `${eventType}ErrorEvent`,
235→        eventParentIds: [...startedEvent.eventParentIds, startedEvent.eventId],
236→        data: {
237→          error: error instanceof Error ? error.message : String(error),
238→          durationMs:
239→            Date.now() - new Date(startedEvent.eventCreatedAt).getTime(),
240→        },
241→      });
242→      throw error;
243→    } finally {
244→      // Pop only the frame owned by this wrapper. If nested code has already
245→      // mutated the stack unexpectedly, we skip the completed event rather than
246→      // emitting a misleading lifecycle edge.
247→      const parentEvent = ctx.parentEvents.pop();
248→      if (parentEvent?.eventId === startedEvent.eventId && !caughtError) {
249→        FlowLogger.emit({
250→          eventType: `${eventType}CompletedEvent`,
251→          eventParentIds: [
252→            ...startedEvent.eventParentIds,
253→            startedEvent.eventId,
254→          ],
255→          data: {
256→            durationMs:
257→              Date.now() - new Date(startedEvent.eventCreatedAt).getTime(),
258→          },
259→        });
260→      }
261→    }
262→  }
263→
264→  // Emits a CDP event under a caller-supplied context. CDP transport code uses this
265→  // instead of `runWithLogging()` because request/response/message events
266→  // are separate lifecycle edges with explicit parent ids.
267→  private static logCdpEvent(
268→    context: FlowLoggerContext,
269→    eventType: CdpLogEventType,
270→    { method, params, result, error, targetId }: CdpLogPayload,
271→    eventParentIds?: string[],
272→  ): FlowEvent | null {
273→    if (method.endsWith(".enable") || method === "enable") {
274→      return null;
275→    }
276→
277→    if (eventType === "message" && FlowLogger.NOISY_CDP_EVENTS.has(method)) {
278→      return null;
279→    }
280→
281→    return loggerContext.run(FlowLogger.cloneContext(context), () =>
282→      FlowLogger.emit({
283→        eventType: CDP_EVENT_NAMES[eventType],
284→        eventParentIds,
285→        data: {
286→          method,
287→          params,
288→          result,
289→          error,
290→          targetId,
291→        },
292→      }),
293→    );
294→  }
295→
296→  // Emits an LLM request/response event only when a flow context is active.
297→  // LLM logging is best-effort, so callers should not fail if it is invoked outside a tracked async chain.
298→  private static emitLlmEvent(event: FlowEventInput): void {
299→    const context = FlowLogger.resolveContext();
300→    if (!context) {
301→      return;
302→    }
303→
304→    loggerContext.run(context, () => {
305→      FlowLogger.emit(event);
306→    });
307→  }
308→
309→  // Builds the one-line prompt summary used in LLM request events for AI SDK middleware calls.
310→  private static buildMiddlewarePromptSummary(params: {
311→    prompt?: unknown;
312→    tools?: unknown;
313→  }): string {
314→    const toolCount = Array.isArray(params.tools) ? params.tools.length : 0;
315→    const messages = (params.prompt ?? []) as Array<{
316→      role?: string;
317→      content?: unknown;
318→    }>;
319→    const lastMsg = messages
320→      .filter((message) => message.role !== "system")
321→      .pop();
322→    let rolePrefix = lastMsg?.role ?? "?";
323→    let promptSummary = `(no text) +{${toolCount} tools}`;
324→
325→    if (!lastMsg) {
326→      return `?: ${promptSummary}`;
327→    }
328→
329→    if (typeof lastMsg.content === "string") {
330→      promptSummary = `${lastMsg.content} +{${toolCount} tools}`;
331→    } else if (Array.isArray(lastMsg.content)) {
332→      const toolResult = (
333→        lastMsg.content as Array<{
334→          type?: string;
335→          toolName?: string;
336→          output?: { type?: string; value?: unknown };
337→        }>
338→      ).find((part) => part.type === "tool-result");
339→
340→      if (toolResult) {
341→        rolePrefix = `tool result: ${toolResult.toolName}()`;
342→        if (toolResult.output?.type === "json" && toolResult.output.value) {
343→          promptSummary = `${JSON.stringify(toolResult.output.value)} +{${toolCount} tools}`;
344→        } else if (Array.isArray(toolResult.output?.value)) {
345→          promptSummary = `${
346→            extractLlmMessageSummary({
347→              content: toolResult.output.value,
348→            }) ?? "(no text)"
349→          } +{${toolCount} tools}`;
350→        }
351→      } else {
352→        promptSummary = `${
353→          extractLlmMessageSummary({ content: lastMsg.content }) ?? "(no text)"
354→        } +{${toolCount} tools}`;
355→      }
356→    }
357→
358→    return `${rolePrefix}: ${promptSummary}`;
359→  }
360→
361→  // Builds the one-line output summary used in LLM response events for AI SDK middleware calls.
362→  private static buildMiddlewareOutputSummary(result: {
363→    text?: string;
364→    content?: unknown;
365→    toolCalls?: unknown[];
366→  }): string {
367→    let outputSummary = result.text || "";
368→    if (!outputSummary && result.content) {
369→      if (typeof result.content === "string") {
370→        outputSummary = result.content;
371→      } else if (Array.isArray(result.content)) {
372→        outputSummary = (
373→          result.content as Array<{
374→            type?: string;
375→            text?: string;
376→            toolName?: string;
377→          }>
378→        )
379→          .map((contentPart) => {
380→            if (contentPart.text) {
381→              return contentPart.text;
382→            }
383→
384→            if (contentPart.type === "tool-call") {
385→              return `tool call: ${contentPart.toolName}()`;
386→            }
387→
388→            return `[${contentPart.type}]`;
389→          })
390→          .join(" ");
391→      }
392→    }
393→
394→    if (!outputSummary && result.toolCalls?.length) {
395→      return `[${result.toolCalls.length} tool calls]`;
396→    }
397→
398→    return outputSummary || "[empty]";
399→  }
