405→  // Initialize a new logging context. Call this at the start of a session.
406→  static init(
407→    sessionId: string,
408→    eventBus: EventEmitterWithWildcardSupport,
409→  ): FlowLoggerContext {
410→    const ctx: FlowLoggerContext = {
411→      sessionId,
412→      eventBus,
413→      parentEvents: [],
414→    };
415→
416→    loggerContext.enterWith(ctx);
417→    return ctx;
418→  }
