420→  // Clears the parent stack for a session when a V3 instance shuts down.
421→  // This does not emit a final event; it just tears down in-memory context.
422→  static async close(context?: FlowLoggerContext | null): Promise<void> {
423→    const ctx = context ?? loggerContext.getStore() ?? null;
424→    if (!ctx) return;
425→    ctx.parentEvents = [];
426→  }
427→
428→  // Returns the current ALS-backed flow context and throws when code
429→  // executes outside a tracked flow. Use `resolveContext()` for best-effort lookups.
430→  static get currentContext(): FlowLoggerContext {
431→    const ctx = loggerContext.getStore() ?? null;
432→    if (!ctx) {
433→      throw new Error("FlowLogger context is missing.");
434→    }
435→
436→    return ctx;
437→  }
438→
439→  // Returns a cloned FlowLogger context for the current async call-chain when one exists,
440→  // otherwise falls back to the provided instance-owned context.
441→  // This is the non-throwing lookup for callers that can continue without ALS.
442→  static resolveContext(
443→    fallbackContext?: FlowLoggerContext | null,
444→  ): FlowLoggerContext | null {
445→    const currentContext = loggerContext.getStore() ?? null;
446→    if (currentContext) {
447→      return FlowLogger.cloneContext(currentContext);
448→    }
449→
450→    return fallbackContext ? FlowLogger.cloneContext(fallbackContext) : null;
451→  }
452→
453→  // Decorator-style wrapper used on class methods that should emit their own started/completed/error envelope.
454→  // It resolves the flow context from either the decorator options or `this.flowLoggerContext`,
455→  // then delegates the actual lifecycle handling to `runWithLogging()`.
456→  static wrapWithLogging<TMethod extends AsyncOriginalMethod>(
457→    options: FlowLoggerLogOptions,
458→  ) {
459→    return function <
460→      TWrappedMethod extends AsyncOriginalMethod<
461→        Parameters<TMethod>,
462→        Awaited<ReturnType<TMethod>>,
463→        ThisParameterType<TMethod>
464→      >,
465→    >(originalMethod: TWrappedMethod): TWrappedMethod {
466→      const wrappedMethod = async function (
467→        this: ThisParameterType<TWrappedMethod>,
468→        ...args: Parameters<TWrappedMethod>
469→      ): Promise<Awaited<ReturnType<TWrappedMethod>>> {
470→        let context = options.context;
471→        if (!context) {
472→          context = (
473→            this as { flowLoggerContext?: FlowLoggerContext } | null | undefined
474→          )?.flowLoggerContext;
475→        }
476→
477→        return await FlowLogger.runWithLogging(
478→          {
479→            ...options,
480→            context,
481→          },
482→          (...boundArgs: Parameters<TWrappedMethod>) =>
483→            originalMethod.apply(this, boundArgs) as Promise<
484→              Awaited<ReturnType<TWrappedMethod>>
485→            >,
486→          args,
487→        );
488→      };
489→
490→      return wrappedMethod as unknown as TWrappedMethod;
491→    };
492→  }
493→
494→  // Wraps an async function or zero-arg closure with flow events.
495→  // This is the imperative entrypoint used by handlers that cannot use the decorator form.
496→  // Standard case: the logged params are the same tuple passed to the wrapped method.
497→  static runWithLogging<TMethod extends AsyncOriginalMethod>(
498→    options: FlowLoggerLogOptions,
499→    originalMethod: TMethod,
500→    params: Readonly<Parameters<TMethod>>,
501→  ): Promise<Awaited<ReturnType<TMethod>>>;
502→  // Special case: log an arbitrary params tuple while executing a zero-arg closure.
503→  static runWithLogging<TResult>(
504→    options: FlowLoggerLogOptions,
505→    originalMethod: AsyncOriginalMethod<[], TResult>,
506→    params: ReadonlyArray<unknown>,
507→  ): Promise<Awaited<TResult>>;
508→  static runWithLogging(
509→    options: FlowLoggerLogOptions,
510→    originalMethod: AsyncOriginalMethod<unknown[], unknown>,
511→    params: ReadonlyArray<unknown>,
512→  ): Promise<unknown> {
513→    const eventData = {
514→      ...(options.data ?? {}),
515→      params: [...params],
516→    };
517→
518→    const execute = (): Promise<unknown> =>
519→      FlowLogger.runWithAutoStatusEventLogging(
520→        {
521→          ...options,
522→          data: eventData,
523→        },
524→        () => originalMethod(...params),
525→      );
526→
527→    // No explicit context and no active ALS means there is nothing to attach
528→    // this work to, so we leave execution untouched instead of fabricating a
529→    // root event.
530→    if (!options.context && !(loggerContext.getStore() ?? null)) {
531→      return originalMethod(...params);
532→    }
533→
534→    if (options.context) {
535→      // Re-enter the caller-owned context so wrapper events land under the same
536→      // session tree even when this code executes outside the original ALS
537→      // chain.
538→      return loggerContext.run(
539→        FlowLogger.resolveReentryContext(options.context),
540→        execute,
541→      );
542→    }
543→
544→    return execute();
545→  }
546→
547→  // Re-enters an existing FlowLogger context without emitting wrapper events.
548→  // Use this when work already belongs to a known parent and needs AsyncLocalStorage set manually.
549→  static withContext<T>(context: FlowLoggerContext, fn: () => T): T {
550→    return loggerContext.run(FlowLogger.resolveReentryContext(context), fn);
551→  }
