709→// =============================================================================
710→// LLM Event Extraction Helpers
711→// =============================================================================
712→
713→type ContentPart = {
714→  type?: string;
715→  text?: string;
716→  content?: unknown[];
717→  source?: { data?: string };
718→  image_url?: { url?: string };
719→  inlineData?: { data?: string };
720→};
721→
722→type LlmMessageContent = {
723→  content?: unknown;
724→  text?: string;
725→  parts?: unknown[];
726→};
727→
728→// Extracts text and image markers from an LLM content array.
729→// This is shared by the request-summary helpers below so different provider message
730→// shapes render consistently in the flow log.
731→function extractLlmMessageContent(content: unknown[]): {
732→  text?: string;
733→  extras: string[];
734→} {
735→  const result = {
736→    text: undefined as string | undefined,
737→    extras: [] as string[],
738→  };
739→
740→  for (const part of content) {
741→    const p = part as ContentPart;
742→    // Text
743→    if (!result.text && p.text) {
744→      result.text = p.type === "text" || !p.type ? p.text : undefined;
745→    }
746→    // Images - various formats
747→    if (p.type === "image" || p.type === "image_url") {
748→      const url = p.image_url?.url;
749→      if (url?.startsWith("data:"))
750→        result.extras.push(`${dataToKb(url)}kb image`);
751→      else if (p.source?.data)
752→        result.extras.push(`${dataToKb(p.source.data)}kb image`);
753→      else result.extras.push("image");
754→    } else if (p.source?.data) {
755→      result.extras.push(`${dataToKb(p.source.data)}kb image`);
756→    } else if (p.inlineData?.data) {
757→      result.extras.push(`${dataToKb(p.inlineData.data)}kb image`);
758→    }
759→    // Recurse into tool_result content
760→    if (p.type === "tool_result" && Array.isArray(p.content)) {
761→      const nested = extractLlmMessageContent(p.content);
762→      if (!result.text && nested.text) {
763→        result.text = nested.text;
764→      }
765→      result.extras.push(...nested.extras);
766→    }
767→  }
768→
769→  return result;
770→}
771→
772→// Produces a single compact summary from a provider-specific message payload
773→// so request and tool-result logs stay readable.
774→function extractLlmMessageSummary(
775→  input: LlmMessageContent,
776→  options?: {
777→    trimInstructionPrefix?: boolean;
778→    extras?: string[];
779→  },
780→): string | undefined {
781→  const result = {
782→    text: undefined as string | undefined,
783→    extras: [...(options?.extras ?? [])],
784→  };
785→
786→  if (typeof input.content === "string") {
787→    result.text = input.content;
788→  } else if (typeof input.text === "string") {
789→    result.text = input.text;
790→  } else if (Array.isArray(input.parts)) {
791→    const summary = extractLlmMessageContent(input.parts);
792→    result.text = summary.text;
793→    result.extras.push(...summary.extras);
794→  } else if (Array.isArray(input.content)) {
795→    const summary = extractLlmMessageContent(input.content);
796→    result.text = summary.text;
797→    result.extras.push(...summary.extras);
798→  }
799→
800→  if (options?.trimInstructionPrefix && result.text) {
801→    result.text = result.text.replace(/^[Ii]nstruction: /, "");
802→  }
803→
804→  const text = result.text;
805→  if (!text && result.extras.length === 0) return undefined;
806→
807→  let summary = text || "";
808→  if (result.extras.length > 0) {
809→    const extrasStr = result.extras.map((e) => `+{${e}}`).join(" ");
810→    summary = summary ? `${summary} ${extrasStr}` : extrasStr;
811→  }
812→  return summary || undefined;
813→}
814→
815→// Formats the last user-facing prompt into the one-line form used by standard LLM request logs,
816→// for example: `some text +{5.8kb image} +{schema}`.
817→export function extractLlmPromptSummary(
818→  messages: Array<{ role: string; content: unknown }>,
819→  options?: { toolCount?: number; hasSchema?: boolean },
820→): string | undefined {
821→  try {
822→    const lastUserMsg = messages.filter((m) => m.role === "user").pop();
823→    if (!lastUserMsg) return undefined;
824→
825→    return extractLlmMessageSummary(lastUserMsg, {
826→      trimInstructionPrefix: true,
827→      extras: [
828→        ...(options?.hasSchema ? ["schema"] : []),
829→        ...(options?.toolCount ? [`${options.toolCount} tools`] : []),
830→      ],
831→    });
832→  } catch {
833→    return undefined;
834→  }
835→}
836→
837→// Extract a text summary from CUA-style messages. This accepts Anthropic, OpenAI, and Google-style payloads.
838→export function extractLlmCuaPromptSummary(
839→  messages: unknown[],
840→): string | undefined {
841→  try {
842→    const lastMsg = messages
843→      .filter((m) => {
844→        const msg = m as { role?: string; type?: string };
845→        return msg.role === "user" || msg.type === "tool_result";
846→      })
847→      .pop() as
848→      | { content?: unknown; parts?: unknown[]; text?: string }
849→      | undefined;
850→
851→    if (!lastMsg) return undefined;
852→
853→    return extractLlmMessageSummary(lastMsg);
854→  } catch {
855→    return undefined;
856→  }
857→}
858→
859→// Formats the response side of a CUA exchange into a single short log line.
860→export function extractLlmCuaResponseSummary(output: unknown): string {
861→  try {
862→    const items: unknown[] =
863→      (output as { candidates?: [{ content?: { parts?: unknown[] } }] })
864→        ?.candidates?.[0]?.content?.parts ??
865→      (Array.isArray(output) ? output : []);
866→
867→    const summary = items
868→      .map((item) => {
869→        const i = item as {
870→          type?: string;
871→          text?: string;
872→          name?: string;
873→          functionCall?: { name?: string };
874→        };
875→        if (i.text) return i.text;
876→        if (i.functionCall?.name) return i.functionCall.name;
877→        if (i.type === "tool_use" && i.name) return i.name;
878→        return i.type ?? "[item]";
879→      })
880→      .join(" ");
881→
882→    return summary;
883→  } catch {
884→    return "[error]";
885→  }
886→}
