 22→// Checks whether an event matches a query used by queryable sinks. `eventId` matches both the event itself and descendants of that event.
 23→function matchesEventStoreQuery(
 24→  event: FlowEvent,
 25→  query: EventStoreQuery,
 26→): boolean {
 27→  if (query.sessionId && event.sessionId !== query.sessionId) return false;
 28→
 29→  if (query.eventId) {
 30→    const matchesEvent =
 31→      event.eventId === query.eventId ||
 32→      event.eventParentIds.includes(query.eventId);
 33→    if (!matchesEvent) {
 34→      return false;
 35→    }
 36→  }
 37→
 38→  if (query.eventType) {
 39→    const pattern = new RegExp(
 40→      `^${query.eventType
 41→        .replace(/[.*+?^${}()|[\]\\]/g, "\\$&")
 42→        .replace(/\\\*/g, ".*")}$`,
 43→    );
 44→    if (!pattern.test(event.eventType)) {
 45→      return false;
 46→    }
 47→  }
 48→
 49→  return true;
 50→}
