 56→// Returns true when a file sink's stream is still open and writable.
 57→function isWritable(stream: fs.WriteStream | null): stream is fs.WriteStream {
 58→  return !!(stream && !stream.destroyed && stream.writable);
 59→}
 60→
 61→// Writes a serialized event to a file sink and converts callback-style stream completion into a promise.
 62→function writeToStream(stream: fs.WriteStream, value: string): Promise<void> {
 63→  return new Promise<void>((resolve, reject) => {
 64→    try {
 65→      stream.write(value, (error?: Error | null) => {
 66→        if (error) {
 67→          reject(error);
 68→          return;
 69→        }
 70→        resolve();
 71→      });
 72→    } catch (error) {
 73→      reject(error);
 74→    }
 75→  });
 76→}
