 82→abstract class FileEventSink implements EventSink {
 83→  private readonly streamPromise: Promise<fs.WriteStream | null>; // Lazily opens the one file stream owned by this sink when the session directory resolves.
 84→
 85→  // Creates a best-effort file sink bound to a single session directory.
 86→  constructor(sessionDirPromise: Promise<string | null>, fileName: string) {
 87→    this.streamPromise = sessionDirPromise.then((sessionDir) =>
 88→      sessionDir
 89→        ? fs.createWriteStream(path.join(sessionDir, fileName), { flags: "a" })
 90→        : null,
 91→    );
 92→  }
 93→
 94→  protected abstract serialize(event: FlowEvent): Promise<string | null>;
 95→
 96→  // Serializes and appends a single event. File sinks are intentionally best-effort and never allowed to affect library execution flow.
 97→  async emit(event: FlowEvent): Promise<void> {
 98→    try {
 99→      const stream = await this.streamPromise;
100→      if (!isWritable(stream)) {
101→        return;
102→      }
103→
104→      const serialized = await this.serialize(event);
105→      if (!serialized) {
106→        return;
107→      }
108→
109→      await writeToStream(stream, serialized);
110→    } catch {
111→      // best effort only
112→    }
113→  }
114→
115→  // File sinks are write-only and do not support query reads.
116→  async query(): Promise<FlowEvent[]> {
117→    return [];
118→  }
119→
120→  // Closes the underlying file stream when the owning store shuts down.
121→  async destroy(): Promise<void> {
122→    const stream = await this.streamPromise.catch((): null => null);
123→    if (!isWritable(stream)) {
124→      return;
125→    }
126→
127→    await new Promise<void>((resolve) => {
128→      stream.end(resolve);
129→    });
130→  }
131→}
